gSO(){return"Higher chance of sailing to Skull Island"},
gSy(){return"Guard"},
gSv(){return"Once during your turn, you may reroll a single thrown skull on its own. If you reach 3 skulls at any point, your turn ends immediately and you can no longer use this."},
