gSx(){return"3 skulls still end your turn immediately, even before you can use this"},
gSn(){return"Battleship"},
gSj(){return"You must throw at least the number of sabres shown on the card, then stop your turn voluntarily. Succeed, and you score bonus points on top of your usual score. Fail, and you score nothing and lose points instead. You can never sail to Skull Island with this card."},
gSk(){return"Must throw at least the shown number of sabres, then stop voluntarily"},
gSm(){return"Fail to reach that number and you score 0 points, plus a penalty"},
gSl(){return"Sailing to Skull Island is not possible with this card"},
gSq(){return"Coin"},
gSo(){return"Your turn starts with an extra gold coin, which counts either on its own or as part of a combination."},
